import{_ as o,c as a,o as i,aj as l}from"./chunks/framework.VtnL2jmu.js";const p=JSON.parse('{"title":"Micro 现代化的终端编辑器","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/Micro 现代化的终端编辑器.md","filePath":"Linux/Micro 现代化的终端编辑器.md"}'),r={name:"Linux/Micro 现代化的终端编辑器.md"};function t(c,e,s,d,n,h){return i(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="micro-现代化的终端编辑器" tabindex="-1">Micro 现代化的终端编辑器 <a class="header-anchor" href="#micro-现代化的终端编辑器" aria-label="Permalink to “Micro 现代化的终端编辑器”">​</a></h1><hr><h3 id="_1-为什么-micro-是-nano-的终极替代品" tabindex="-1">1. 为什么 Micro 是 Nano 的终极替代品？ <a class="header-anchor" href="#_1-为什么-micro-是-nano-的终极替代品" aria-label="Permalink to “1. 为什么 Micro 是 Nano 的终极替代品？”">​</a></h3><ul><li><strong>真正的鼠标支持</strong>：你可以直接用鼠标点击定位、滚动轮翻页、甚至<strong>拖拽选中</strong>代码（这在普通终端编辑器里是奢侈品）。</li><li><strong>现代快捷键</strong>：它支持 <code>Ctrl+C</code> (复制)、<code>Ctrl+V</code> (粘贴)、<code>Ctrl+S</code> (保存)、<code>Ctrl+F</code> (搜索)。你不需要学习像 Vim 那种反直觉的指令。</li><li><strong>原生高亮</strong>：默认支持 75+ 种语言（Java, SQL, YAML, JSON 等），效果非常出色。</li><li><strong>内置终端</strong>：按 <code>Ctrl+E</code> 然后输入 <code>term</code>，你可以在编辑器里直接开一个分屏终端跑 Maven 命令。</li></ul><hr><h3 id="_2-安装-极简安装" tabindex="-1">2. 安装（极简安装） <a class="header-anchor" href="#_2-安装-极简安装" aria-label="Permalink to “2. 安装（极简安装）”">​</a></h3><p>依然推荐通过包管理器或脚本安装，它是一个单一的 Go 二进制文件，非常纯净：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>sudo apt install micro</span></span></code></pre></div><hr><h3 id="_3-核心功能与你的-格式化-诉求" tabindex="-1">3. 核心功能与你的“格式化”诉求 <a class="header-anchor" href="#_3-核心功能与你的-格式化-诉求" aria-label="Permalink to “3. 核心功能与你的“格式化”诉求”">​</a></h3><p>Micro 解决你“格式化”疑惑的姿势非常优雅：</p><h4 id="_1-强大的插件系统" tabindex="-1">① 强大的插件系统 <a class="header-anchor" href="#_1-强大的插件系统" aria-label="Permalink to “① 强大的插件系统”">​</a></h4><p>Micro 支持插件，你可以安装格式化插件。按 <code>Ctrl+E</code> 进入命令模式，输入：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>plugin install fmt</span></span></code></pre></div><p>它会自动调用系统中的格式化工具（如 <code>gofmt</code> 或其他）。</p><h4 id="_2-联动外部工具-万能格式化" tabindex="-1">② 联动外部工具（万能格式化） <a class="header-anchor" href="#_2-联动外部工具-万能格式化" aria-label="Permalink to “② 联动外部工具（万能格式化）”">​</a></h4><p>如果你想用我们刚才聊的 <code>jq</code> 格式化当前编辑的 JSON，在 Micro 里只需要：</p><ol><li>按 <code>Ctrl+E</code>。</li><li>输入 <code>run jq .</code> (这会把当前文件内容喂给 jq 处理)。</li><li>或者直接配置一个快捷键。</li></ol><hr><h3 id="_4-实战提效技巧" tabindex="-1">4. 实战提效技巧 <a class="header-anchor" href="#_4-实战提效技巧" aria-label="Permalink to “4. 实战提效技巧”">​</a></h3><h4 id="分屏操作-全栈开发刚需" tabindex="-1">分屏操作（全栈开发刚需） <a class="header-anchor" href="#分屏操作-全栈开发刚需" aria-label="Permalink to “分屏操作（全栈开发刚需）”">​</a></h4><p>在开发 Spring Boot 时，你可能想左边看 <code>Service</code>，右边看 <code>Controller</code>：</p><ul><li><code>Ctrl+E</code> 键入 <code>vsplit UserService.java</code>：垂直分屏。</li><li><code>Ctrl+E</code> 键入 <code>hsplit log.txt</code>：水平分屏。</li><li><code>Alt+,</code> 和 <code>Alt+.</code> 在分屏间来回穿梭。</li></ul><h4 id="多光标编辑" tabindex="-1">多光标编辑 <a class="header-anchor" href="#多光标编辑" aria-label="Permalink to “多光标编辑”">​</a></h4><p>这是 Micro 媲美 VS Code 的地方：</p><ul><li>按住 <code>Ctrl</code> 点击不同行，或者按 <code>Alt-n</code> 选择下一个匹配项。</li><li>你可以同时修改多行代码，这在批量修改 <code>application.yml</code> 配置时非常爽。</li></ul><h2 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to “附录”">​</a></h2><h3 id="_1-快捷键-回归人类直觉" tabindex="-1">1. 快捷键：回归人类直觉 <a class="header-anchor" href="#_1-快捷键-回归人类直觉" aria-label="Permalink to “1. 快捷键：回归人类直觉”">​</a></h3><p>Micro 最大的卖点就是它支持你在 Windows 或浏览器里已经养成的习惯：</p><ul><li><strong>保存</strong>：<code>Ctrl + S</code></li><li><strong>复制 / 剪切 / 粘贴</strong>：<code>Ctrl + C</code> / <code>Ctrl + X</code> / <code>Ctrl + V</code></li><li><strong>撤销 / 重做</strong>：<code>Ctrl + Z</code> / <code>Ctrl + Y</code></li><li><strong>查找</strong>：<code>Ctrl + F</code></li><li><strong>全选</strong>：<code>Ctrl + A</code></li><li><strong>退出</strong>：<code>Ctrl + Q</code>（如果文件没保存，它会温柔地询问你）</li></ul><hr><h3 id="_2-核心命门-命令模式-ctrl-e" tabindex="-1">2. 核心命门：命令模式 (<code>Ctrl + E</code>) <a class="header-anchor" href="#_2-核心命门-命令模式-ctrl-e" aria-label="Permalink to “2. 核心命门：命令模式 (Ctrl + E)”">​</a></h3><p>就像 IDEA 的 <code>Shift + Shift</code> 或 VS Code 的 <code>Ctrl + Shift + P</code>，在 Micro 里，几乎所有高级功能都通过按 <strong><code>Ctrl + E</code></strong> 调出底部的命令行。</p><p>常用命令：</p><ul><li><strong><code>help</code></strong>：查看自带的详细教程。</li><li><strong><code>set [option] [value]</code></strong>：修改配置。例如 <code>set colorscheme solarized</code>。</li><li><strong><code>plugin install [name]</code></strong>：安装插件。</li><li><strong><code>vsplit</code> / <code>hsplit</code></strong>：垂直或水平分屏编辑。</li></ul><hr><h3 id="_3-分屏开发技巧" tabindex="-1">3. 分屏开发技巧 <a class="header-anchor" href="#_3-分屏开发技巧" aria-label="Permalink to “3. 分屏开发技巧”">​</a></h3><p>开发 Spring Boot 时，你经常需要对照两个文件。Micro 的分屏非常直观：</p><ol><li><strong>开启分屏</strong>：按 <code>Ctrl + E</code> 输入 <code>vsplit UserService.java</code>。</li><li><strong>切换焦点</strong>：按 <code>Alt + ,</code> 或 <code>Alt + .</code> 在左右窗口间跳转。</li><li><strong>关闭窗口</strong>：直接在那个窗口按 <code>Ctrl + Q</code>。</li></ol><hr><h3 id="_4-鼠标操作-nano-做不到的事" tabindex="-1">4. 鼠标操作（Nano 做不到的事） <a class="header-anchor" href="#_4-鼠标操作-nano-做不到的事" aria-label="Permalink to “4. 鼠标操作（Nano 做不到的事）”">​</a></h3><ul><li><strong>直接点击</strong>：鼠标点哪里，光标就闪在哪里。</li><li><strong>拖拽选中</strong>：用鼠标划选一段代码，直接按 <code>Ctrl + C</code> 复制。</li><li><strong>滚动滚轮</strong>：在终端里也能像看网页一样快速翻阅代码。</li></ul><hr><h3 id="_5-格式化与自动提示" tabindex="-1">5. 格式化与自动提示 <a class="header-anchor" href="#_5-格式化与自动提示" aria-label="Permalink to “5. 格式化与自动提示”">​</a></h3><ul><li><strong>语法高亮</strong>：它会自动识别你的 <code>.java</code>、<code>.yml</code>、<code>.sql</code> 扩展名。如果没识别出来，按 <code>Ctrl + E</code> 输入 <code>set filetype java</code>。</li><li><strong>自动缩进</strong>：它比 Nano 聪明得多，回车会自动对齐上一行的缩进级别。</li><li><strong>行号显示</strong>：默认开启，方便你定位 Spring Boot 报错堆栈里的具体行数。</li></ul><hr><h3 id="_6-配置持久化" tabindex="-1">6. 配置持久化 <a class="header-anchor" href="#_6-配置持久化" aria-label="Permalink to “6. 配置持久化”">​</a></h3><p>Micro 的配置文件位于 <code>~/.config/micro/settings.json</code>。你也可以通过命令模式直接改并保存。</p><p>如果你习惯用鼠标滚轮，但发现有时候会进入“选中模式”，可以尝试：</p><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 在 micro 内部按 Ctrl+E 执行</span></span>
<span class="line"><span>set mouse true</span></span></code></pre></div>`,51)])])}const _=o(r,[["render",t]]);export{p as __pageData,_ as default};
